<span class="line">    <span class="token literal-property property">totalPrice</span><span class="token operator">:</span> state<span class="token punctuation">.</span>totalPrice <span class="token operator">+</span> product<span class="token punctuation">.</span>price<span class="token punctuation">,</span></span>
