<span class="line">  <span class="token keyword">const</span> totalPrice <span class="token operator">=</span> <span class="token function">useCartStore</span><span class="token punctuation">(</span><span class="token parameter">state</span> <span class="token operator">=&gt;</span> state<span class="token punctuation">.</span>totalPrice<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
